class Solution {
    public List<Integer> powerfulIntegers(int x, int y, int bound) {
        Set<Integer> powerful = new HashSet<>();
        for (int i = 0; x^i <= bound; i++) {
            for (int j = 0; y^j <= bound; j++) {
                powerful.add(x^i + y^j);
            }
        }
        return new ArrayList<>(powerful);
    }
}
